namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();
    private DateTime _lastAutoAdd;

    public NotificationService()
    {
        // Seed initial fake data
        _notifications.Add(new(_nextId++, "Welcome to the notification center!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new(_nextId++, "Your profile was updated successfully.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new(_nextId++, "New feature: dark mode is now available.", DateTime.UtcNow.AddMinutes(-2)));
        _lastAutoAdd = DateTime.UtcNow;
    }

    /// <summary>Returns all notifications available right now.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            MaybeAddNew();
            return _notifications.OrderByDescending(n => n.Timestamp).ToList();
        }
    }

    /// <summary>Returns only notifications with Id greater than <paramref name="sinceId"/>.</summary>
    public List<Notification> GetSince(int sinceId)
    {
        lock (_lock)
        {
            MaybeAddNew();
            return _notifications
                .Where(n => n.Id > sinceId)
                .OrderByDescending(n => n.Timestamp)
                .ToList();
        }
    }

    // Automatically generates a new notification roughly every 8-15 seconds
    // so polling has something to find.
    private void MaybeAddNew()
    {
        if ((DateTime.UtcNow - _lastAutoAdd).TotalSeconds < 8)
            return;

        _lastAutoAdd = DateTime.UtcNow;
        string[] messages =
        [
            "Deployment to production completed.",
            "You have a new follower.",
            "Scheduled maintenance tonight at 11 PM.",
            "Your report is ready to download.",
            "Security alert: new login from unknown device.",
            "Backup completed successfully.",
        ];
        var msg = messages[(_nextId - 1) % messages.Length];
        _notifications.Add(new(_nextId++, msg, DateTime.UtcNow));
    }
}

@page "/notifications"
@using NotificationsApp.Services
@implements IDisposable
@inject NotificationService Svc
@rendermode @(new InteractiveServerRenderMode(prerender: true))

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group mt-3">
        @foreach (var n in _notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>
                    <strong>#@n.Id</strong> &mdash; @n.Message
                </div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private int _latestId;

    // Runs during SSR *and* when the component initialises interactively.
    // PersistentComponentState is the standard way to avoid double-fetching,
    // but for a simple list we can use a cheaper trick: track the latest Id
    // we already have and only ask for newer ones once polling starts.
    protected override void OnInitialized()
    {
        _notifications = Svc.GetAll();
        _latestId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
    }

    // Called only on the interactive (SignalR) render — never during static SSR.
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollLoopAsync(_cts.Token);
        }
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);
            }
            catch (OperationCanceledException)
            {
                break;
            }

            var newer = Svc.GetSince(_latestId);
            if (newer.Count > 0)
            {
                _notifications.InsertRange(0, newer);
                _latestId = _notifications.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

