+    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
+</h1>
+
+@if (_notifications.Count == 0)
+{
+    <p><em>No notifications yet.</em></p>
+}
+else
+{
+    <ul class="list-group mt-3">
+        @foreach (var n in _notifications)
+        {
+            <li class="list-group-item d-flex justify-content-between align-items-start">
+                <div>
+                    <strong>#@n.Id</strong> &mdash; @n.Message
+                </div>
+                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
+            </li>
+        }
+    </ul>
+}
+
+@code {
+    private List<Notification> _notifications = new();
+    private CancellationTokenSource? _cts;
+    private int _latestId;
+
+    // Runs during SSR *and* when the component initialises interactively.
+    // PersistentComponentState is the standard way to avoid double-fetching,
+    // but for a simple list we can use a cheaper trick: track the latest Id
+    // we already have and only ask for newer ones once polling starts.
+    protected override void OnInitialized()
+    {
+        _notifications = Svc.GetAll();
+        _latestId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
+    }
+
+    // Called only on the interactive (SignalR) render — never during static SSR.
+    protected override void OnAfterRender(bool firstRender)
+    {
+        if (firstRender)
+        {
+            _cts = new CancellationTokenSource();
+            _ = PollLoopAsync(_cts.Token);
+        }
+    }
+
+    private async Task PollLoopAsync(CancellationToken ct)
+    {
+        while (!ct.IsCancellationRequested)
+        {
+            try
+            {
+                await Task.Delay(TimeSpan.FromSeconds(5), ct);
+            }
+            catch (OperationCanceledException)
+            {
+                break;
+            }
+
+            var newer = Svc.GetSince(_latestId);
+            if (newer.Count > 0)
+            {
+                _notifications.InsertRange(0, newer);
+                _latestId = _notifications.Max(n => n.Id);
+                await InvokeAsync(StateHasChanged);
+            }
+        }
+    }
+
+    public void Dispose()
+    {
+        _cts?.Cancel();
+        _cts?.Dispose();
+    }
+}
