namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();
    private DateTime _lastAutoAdd;

    public NotificationService()
    {
        _notifications.Add(new(_nextId++, "Welcome to the notification center!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new(_nextId++, "Your profile was updated successfully.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new(_nextId++, "New feature: dark mode is now available.", DateTime.UtcNow.AddMinutes(-2)));
        _lastAutoAdd = DateTime.UtcNow;
    }

    /// <summary>Returns all notifications available right now.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            MaybeAddNew();
            return _notifications.OrderByDescending(n => n.Timestamp).ToList();
        }
    }

    /// <summary>Returns only notifications with Id greater than <paramref name="sinceId"/>.</summary>
    public List<Notification> GetSince(int sinceId)
    {
        lock (_lock)
        {
            MaybeAddNew();
            return _notifications
                .Where(n => n.Id > sinceId)
                .OrderByDescending(n => n.Timestamp)
                .ToList();
        }
    }

    // Generates a new notification roughly every 8-15 seconds so polling has something to find.
    private void MaybeAddNew()
    {
        if ((DateTime.UtcNow - _lastAutoAdd).TotalSeconds < 8)
            return;

        _lastAutoAdd = DateTime.UtcNow;
        string[] messages =
        [
            "Deployment to production completed.",
            "You have a new follower.",
            "Scheduled maintenance tonight at 11 PM.",
            "Your report is ready to download.",
            "Security alert: new login from unknown device.",
            "Backup completed successfully.",
        ];
        var msg = messages[(_nextId - 1) % messages.Length];
        _notifications.Add(new(_nextId++, msg, DateTime.UtcNow));
    }
}

